solution_code:
#include <iostream>

int main()
{
    int a = 0;
    int b = 0;
    std::cin >> a >> b;

    std::cout << "no parens: " << a + b * 2 << '\n';
    std::cout << "parens add first: " << (a + b) * 2 << '\n';
    std::cout << "parens mul first: " << a + (b * 2) << '\n';

    return 0;
}

